# Fibonacci Number Using Recursion in C++

## Program

```cpp
#include <iostream>
using namespace std;

// Recursive function to find nth Fibonacci number
int fibonacci(int n) {
    // Base cases
    if (n <= 0)
        return 0;
    if (n == 1)
        return 1;

    // Recursive case: F(n) = F(n-1) + F(n-2)
    return fibonacci(n - 1) + fibonacci(n - 2);
}

int main() {
    int n;

    cout << "Enter the value of n: ";
    cin >> n;

    if (n < 0) {
        cout << "Please enter a non-negative number." << endl;
    } else {
        cout << "The " << n << "th Fibonacci number is: " << fibonacci(n) << endl;
    }

    // Display first few Fibonacci numbers
    cout << "\nFibonacci Series (first 15 terms):" << endl;
    for (int i = 0; i < 15; i++) {
        cout << "F(" << i << ") = " << fibonacci(i) << endl;
    }

    return 0;
}
```

